const profile = $('Read Profile').all().map(i => i.json).find(r => r.chat_id) || null;
if (!profile) return [];
const chat_id = profile.chat_id;
const targetKcal = Number(profile.target_kcal) || 0;
const targetProtein = Number(profile.target_protein_g) || 0;
const interval = Number(profile.training_days_interval) || 1;

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const toStr = (d) => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const today = toStr(now);
const startDate = new Date(now.getTime() - 6*86400000);
const startStr = toStr(startDate);
const inRange = (d) => {
  const s = String(d || '');
  return s >= startStr && s <= today;
};

// --- Food --------------------------------------------------------
const foodRows = $('Read Food Log').all().map(i => i.json).filter(r => inRange(r.date));
const dayMap = {};
for (const r of foodRows) {
  const d = String(r.date);
  if (!dayMap[d]) dayMap[d] = { kcal: 0, protein: 0 };
  dayMap[d].kcal    += Number(r.kcal)    || 0;
  dayMap[d].protein += Number(r.protein) || 0;
}
const loggedDays = Object.keys(dayMap);
const avgKcal    = loggedDays.length ? Math.round(loggedDays.reduce((s,d) => s + dayMap[d].kcal,    0) / loggedDays.length) : 0;
const avgProtein = loggedDays.length ? Math.round(loggedDays.reduce((s,d) => s + dayMap[d].protein, 0) / loggedDays.length) : 0;
const proteinHitDays = loggedDays.filter(d => dayMap[d].protein >= (targetProtein - 10)).length;
const proteinHitPct = loggedDays.length ? Math.round(100 * proteinHitDays / loggedDays.length) : 0;

// --- Workouts ---------------------------------------------------
const workoutRows = $('Read Workout Log').all().map(i => i.json).filter(r => inRange(r.date));
const expectedWorkouts = Math.floor(7 / interval);
const wList = workoutRows.map(r => {
  const dur = r.duration_min || '?';
  const burn = r.kcal_burned || '?';
  return `- ${r.day_plan || '?'} — ${dur} мин, ~${burn} ккал`;
}).join('\n');
const workoutKcalTotal = workoutRows.reduce((s, r) => s + (Number(r.kcal_burned) || 0), 0);

// --- Walking ---------------------------------------------------
const walkRows = $('Read Walking Log').all().map(i => i.json).filter(r => inRange(r.date));
const walkDayMap = {};
for (const r of walkRows) {
  const d = String(r.date);
  if (!walkDayMap[d]) walkDayMap[d] = { min: 0, kcal: 0 };
  walkDayMap[d].min  += Number(r.duration_min) || 0;
  walkDayMap[d].kcal += Number(r.kcal_burned)  || 0;
}
const walkDays = Object.keys(walkDayMap).length;
const walkMinTotal  = Object.values(walkDayMap).reduce((s, d) => s + d.min,  0);
const walkKcalTotal = Object.values(walkDayMap).reduce((s, d) => s + d.kcal, 0);
const walkAvgMin = walkDays ? Math.round(walkMinTotal / walkDays) : 0;

// --- Body -------------------------------------------------------
const bodyRows = $('Read Body Params').all().map(i => i.json)
  .filter(r => inRange(r.date))
  .sort((a, b) => String(a.date).localeCompare(String(b.date)));
let weightLine = '⚖️ Вес: данных за неделю нет.';
let fatLine = '';
let weightDelta = null;
if (bodyRows.length >= 2) {
  const first = bodyRows[0];
  const last  = bodyRows[bodyRows.length - 1];
  const w0 = Number(first.weight);
  const w1 = Number(last.weight);
  weightDelta = w1 - w0;
  const dwStr = (weightDelta >= 0 ? '+' : '') + weightDelta.toFixed(1);
  weightLine = `⚖️ Вес: ${w0} → ${w1} кг (${dwStr} кг)`;
  if (first.body_fat_pct && last.body_fat_pct) {
    const f0 = Number(first.body_fat_pct);
    const f1 = Number(last.body_fat_pct);
    const df = f1 - f0;
    const dfStr = (df >= 0 ? '+' : '') + df.toFixed(1);
    fatLine = `\n📉 % жира: ${f0} → ${f1} (${dfStr})`;
  }
} else if (bodyRows.length === 1) {
  weightLine = `⚖️ Вес: ${bodyRows[0].weight} кг (одно измерение, динамики нет)`;
}

// --- Verdict ----------------------------------------------------
let verdict;
if (weightDelta === null) {
  verdict = 'ℹ️ Чтобы видеть динамику, взвешивайся хотя бы 1-2 раза в неделю.';
} else if (weightDelta < -1.2) {
  verdict = '⚠️ Дефицит может быть слишком велик — подними ккал, чтобы не терять мышцы.';
} else if (weightDelta < -0.3) {
  verdict = '✅ Отличный темп! Продолжай в том же духе.';
} else if (weightDelta <= 0.3) {
  verdict = '😐 Темп тормозит — проверь точность подсчёта или добавь активности.';
} else {
  verdict = '⚠️ Вес растёт — пересмотри размеры порций и проверь дефицит.';
}

// --- Build text -------------------------------------------------
const lines = [];
lines.push(`📊 *Итоги недели* (${startStr} — ${today})\n`);
lines.push(`🏋 Тренировок: ${workoutRows.length} из ~${expectedWorkouts} ожидаемых, расход ~${Math.round(workoutKcalTotal)} ккал`);
if (wList) lines.push(wList);
lines.push('');
lines.push(`🚶 Ходьба: ${walkDays} из 7 дней (всего ${walkMinTotal} мин, ~${Math.round(walkKcalTotal)} ккал)`);
if (walkDays) lines.push(`- В среднем ${walkAvgMin} мин в день когда ходил`);
else lines.push('- За неделю ни разу не залогирована ходьба — это слабо при сидячей работе.');
lines.push('');
lines.push(weightLine + fatLine);
lines.push('');
lines.push(`🍽 Еда: ${loggedDays.length} из 7 дней залогированы`);
if (loggedDays.length) {
  lines.push(`- Средние ккал: ${avgKcal} (цель ~${targetKcal})`);
  lines.push(`- Средний белок: ${avgProtein}г (цель ${targetProtein}г)`);
  lines.push(`- Белок добран в ${proteinHitDays} из ${loggedDays.length} дней (${proteinHitPct}%)`);
}
lines.push('');
lines.push(`💡 ${verdict}`);

return [{ json: { chat_id, text: lines.join('\n') } }];
